def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t."""
    n, m = len(s), len(t)
    dp = [0] * (m + 1)
    dp[0] = 1  # Empty string is a subsequence of any string

    for i in range(1, n + 1):
        for j in range(m, 0, -1):
            if s[i - 1] == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
