def num_distinct(s: str, t: str) -> int:
    """Count distinct subsequences of s that equal t using O(m) space."""
    n, m = len(s), len(t)
    if m > n:
        return 0

    # dp[j] will store the number of ways to form t[:j]
    dp = [0] * (m + 1)
    dp[0] = 1

    for char_s in s:
        # Traverse backwards to use results from the previous iteration (i-1)
        for j in range(m, 0, -1):
            if char_s == t[j - 1]:
                dp[j] += dp[j - 1]

    return dp[m]
